# Seed the app-events source index with initial data
kubectl exec -n elasticsearch curl-test -- /bin/sh -c '
cat <<EOF | curl -s -XPOST http://es-http.elasticsearch.svc:9200/_bulk?refresh=true -H "Content-Type: application/x-ndjson" --data-binary @-
{"index":{"_index":"app-events","_id":"seed-1"}}
{"service":"api","@timestamp":"2026-01-01T00:00:00Z"}
{"index":{"_index":"app-events","_id":"seed-2"}}
{"service":"web","@timestamp":"2026-01-01T00:00:01Z"}
{"index":{"_index":"app-events","_id":"seed-3"}}
{"service":"api","@timestamp":"2026-01-01T00:00:02Z"}
EOF
'

# Create the events-by-service transform
kubectl exec -n elasticsearch curl-test -- curl -s -XPUT \
  "http://es-http.elasticsearch.svc:9200/_transform/events-by-service" \
  -H "Content-Type: application/json" \
  -d '{
    "source": {"index": "app-events"},
    "dest": {"index": "app-events-rollup"},
    "pivot": {
      "group_by": {"service": {"terms": {"field": "service.keyword"}}},
      "aggregations": {"event_count": {"value_count": {"field": "service.keyword"}}}
    },
    "sync": {"time": {"field": "@timestamp", "delay": "1s"}}
  }' 2>/dev/null
